//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageamplifyimport("context""errors""time""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/amplify""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry""github.com/hashicorp/terraform-provider-aws/internal/tfresource")const(domainAssociationCreatedTimeout=5*time.MinutedomainAssociationVerifiedTimeout=15*time.Minute)funcwaitDomainAssociationCreated(ctxcontext.Context,conn*amplify.Amplify,appID,domainNamestring)(*amplify.DomainAssociation,error){stateConf:=&retry.StateChangeConf{Pending:[]string{amplify.DomainStatusCreating,amplify.DomainStatusInProgress,amplify.DomainStatusRequestingCertificate},Target:[]string{amplify.DomainStatusPendingVerification,amplify.DomainStatusPendingDeployment,amplify.DomainStatusAvailable},Refresh:statusDomainAssociation(ctx,conn,appID,domainName),Timeout:domainAssociationCreatedTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifv,ok:=outputRaw.(*amplify.DomainAssociation);ok{ifstatus:=aws.StringValue(v.DomainStatus);status==amplify.DomainStatusFailed{tfresource.SetLastError(err,errors.New(aws.StringValue(v.StatusReason)))}returnv,err}returnnil,err}funcwaitDomainAssociationVerified(ctxcontext.Context,conn*amplify.Amplify,appID,domainNamestring)(*amplify.DomainAssociation,error){//nolint:unparamstateConf:=&retry.StateChangeConf{Pending:[]string{amplify.DomainStatusUpdating,amplify.DomainStatusInProgress,amplify.DomainStatusPendingVerification},Target:[]string{amplify.DomainStatusPendingDeployment,amplify.DomainStatusAvailable},Refresh:statusDomainAssociation(ctx,conn,appID,domainName),Timeout:domainAssociationVerifiedTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifv,ok:=outputRaw.(*amplify.DomainAssociation);ok{ifv!=nil&&aws.StringValue(v.DomainStatus)==amplify.DomainStatusFailed{tfresource.SetLastError(err,errors.New(aws.StringValue(v.StatusReason)))}returnv,err}returnnil,err}